const label = env.get('field_label');
const regex = env.get('expected_format');
const scanned = String(msg.payload || '').trim();

let matches = true;
let errorMsg = null;
if (regex) {
    try {
        matches = new RegExp(regex).test(scanned);
        if (!matches) errorMsg = `scanned value does not match expected format: ${regex}`;
    } catch (e) {
        matches = false;
        errorMsg = `invalid regex in expected_format: ${e.message}`;
    }
}

msg.payload = {
    scanned_value: scanned,
    matches_format: matches,
    field_label: label,
    error: errorMsg,
    timestamp: new Date().toISOString()
};
return msg;
